73	};
74	
75	type StoreState = {
76	  modelId?: string;
77	  revision: number;
78	  elementsById: Record<string, Element>;
79	  violations: Violation[];
80	  selectedId?: string;
81	  viewerMode: ViewerMode;
82	  planTool: PlanTool;
83	  activeLevelId?: string;
84	  planPresentationPreset: PlanPresentationPreset;
85	  activePlanViewId?: string;
86	  /** Saved 3D viewpoint whose clip/layer tweaks should persist via `updateElementProperty`. */
87	  activeViewpointId?: string;
88	  /** When set, plan canvas prefers server `planProjectionWire_v1.primitives` (WP-C02/C03). */
89	  planProjectionPrimitives: PlanProjectionPrimitivesV1Wire | null;
90	  /** Last plan wire legend + programme digest readout for workbench panels (Prompt-3 room scheme). */
91	  planRoomSchemeWireReadout: PlanRoomSchemeWireReadout | null;
92	  /** Active Schedules tab row count for browser rendering budget readout (Prompt-8). */
93	  scheduleBudgetHydration: { tab: string; rowCount: number } | null;
