95	  lastLevelElevationPropagationEvidence: LevelElevationPropagationEvidenceV0 | null;
96	  viewerClipElevMm: number | null;
97	  /** Optional lower bound — clips geometry *below* this world Y (mm) for a reproducible slab cut. */
98	  viewerClipFloorElevMm: number | null;
99	  /** When true for a semantic kind (`wall`, `roof`, …), that category is hidden in 3D. */
100	  viewerCategoryHidden: Record<string, boolean>;
