147	  applyOrbitViewpointPreset: (opts: {
148	    capElevMm?: number | null;
149	    floorElevMm?: number | null;
150	    hideSemanticKinds?: string[];
151	  }) => void;
152	  /** Feed Viewport orbital camera rig from element camera mm payload. */
153	  setOrbitCameraFromViewpointMm: (opts: {
154	    position: { xMm: number; yMm: number; zMm: number };
155	    target: { xMm: number; yMm: number; zMm: number };
156	    up: { xMm: number; yMm: number; zMm: number };
