158	
159	  setActivity: (e: ActivityEvent[]) => void;
160	  setIdentity: (userId: string, display: string, peerId: string) => void;
161	};
162	
163	function coerceViolation(v: unknown): Violation {
164	  const vv = v as Record<string, unknown>;
165	  const ruleId =
166	    typeof vv.ruleId === 'string' ? vv.ruleId : typeof vv.rule_id === 'string' ? vv.rule_id : '';
167	  const sev = vv.severity as string | undefined;
168	  const severity =
169	    sev === 'error' || sev === 'warning' || sev === 'info' ? sev : ('warning' as const);
170	  const elementIdsRaw = vv.elementIds ?? vv.element_ids;
171	  const elementIds =
172	    Array.isArray(elementIdsRaw) && elementIdsRaw.every((x) => typeof x === 'string')
173	      ? elementIdsRaw
174	      : [];
175	  const message = typeof vv.message === 'string' ? vv.message : '';
176	  const blocking = typeof vv.blocking === 'boolean' ? vv.blocking : undefined;
177	  const disciplineRaw = vv.discipline ?? vv.Discipline;
178	  const discipline =
179	    typeof disciplineRaw === 'string' && disciplineRaw.length ? disciplineRaw : undefined;
180	  const qf = vv.quickFixCommand ?? vv.quick_fix_command;
181	
182	  const quickFixCommand =
183	    qf !== undefined && qf !== null && typeof qf === 'object'
184	      ? (qf as Record<string, unknown>)
185	      : null;
186	
187	  return {
188	    ruleId,
189	    severity: severity as Violation['severity'],
190	    message,
191	    elementIds,
192	
193	    ...(blocking !== undefined ? { blocking } : {}),
194	
195	    ...(discipline !== undefined ? { discipline } : {}),
196	
197	    ...(quickFixCommand ? { quickFixCommand } : {}),
198	  };
199	}
200	
201	function coerceXY(raw: Record<string, unknown>): { xMm: number; yMm: number } {
202	  return {
203	    xMm: Number(raw.xMm ?? raw.x_mm ?? 0),
204	    yMm: Number(raw.yMm ?? raw.y_mm ?? 0),
205	  };
206	}
207	
208	function coerceXYZ(raw: Record<string, unknown>): { xMm: number; yMm: number; zMm: number } {
209	  return {
210	    xMm: Number(raw.xMm ?? raw.x_mm ?? 0),
211	    yMm: Number(raw.yMm ?? raw.y_mm ?? 0),
212	    zMm: Number(raw.zMm ?? raw.z_mm ?? 0),
213	  };
214	}
215	
216	const _EVIDENCE_REF_KINDS = new Set<EvidenceRefKind>([
217	  'sheet',
218	  'viewpoint',
219	  'plan_view',
220	  'section_cut',
221	  'deterministic_png',
222	]);
223	
224	function coerceEvidenceRefs(rawUnknown: unknown): EvidenceRef[] {
225	  if (!Array.isArray(rawUnknown)) return [];
226	  const refs: EvidenceRef[] = [];
227	  for (const item of rawUnknown) {
228	    if (typeof item !== 'object' || item === null) continue;
229	    const o = item as Record<string, unknown>;
230	    const kindRaw = o.kind;
231	    if (typeof kindRaw !== 'string' || !_EVIDENCE_REF_KINDS.has(kindRaw as EvidenceRefKind)) {
232	      continue;
233	    }
234	    const kind = kindRaw as EvidenceRefKind;
235	    const sheetId =
236	      typeof (o.sheetId ?? o.sheet_id) === 'string' ? String(o.sheetId ?? o.sheet_id) : undefined;
237	    const viewpointId =
238	      typeof (o.viewpointId ?? o.viewpoint_id) === 'string'
239	        ? String(o.viewpointId ?? o.viewpoint_id)
240	        : undefined;
241	    const planViewId =
242	      typeof (o.planViewId ?? o.plan_view_id) === 'string'
243	        ? String(o.planViewId ?? o.plan_view_id)
244	        : undefined;
245	    const sectionCutId =
246	      typeof (o.sectionCutId ?? o.section_cut_id) === 'string'
247	        ? String(o.sectionCutId ?? o.section_cut_id)
248	        : undefined;
