1386	        planProjectionPrimitives: null,
1387	
1388	        planRoomSchemeWireReadout: null,
1389	
1390	        scheduleBudgetHydration: null,
1391	
1392	        lastLevelElevationPropagationEvidence: null,
1393	
1394	        activePlanViewId: pv && merged[pv]?.kind === 'plan_view' ? pv : undefined,
1395	        activeViewpointId: vp && merged[vp]?.kind === 'viewpoint' ? vp : undefined,
1396	      });
1397	    },
1398	
1399	    select: (id) => set({ selectedId: id }),
1400	
1401	    setViewerMode: (m) => set({ viewerMode: m }),
1402	
1403	    setPlanTool: (t) => set({ planTool: t }),
1404	
1405	    setActiveLevelId: (id) => set({ activeLevelId: id }),
1406	
1407	    setOrthoSnapHold: (v) => set({ orthoSnapHold: v }),
1408	
1409	    setPresencePeers: (peers) => set({ presencePeers: peers }),
1410	
1411	    setComments: (c) => set({ comments: c }),
1412	
1413	    mergeComment: (c) =>
1414	      set(() => {
1415	        const nx = [...get().comments.filter((x) => x.id !== c.id), c].sort((a, b) =>
1416	          String(b.createdAt ?? '').localeCompare(String(a.createdAt ?? '')),
1417	        );
1418	
1419	        return { comments: nx };
1420	      }),
1421	
1422	    setPlanHud: (mm) => set({ planHudMm: mm }),
1423	
1424	    setBuildingPreset: (preset) =>
1425	      set(() => {
1426	        try {
1427	          localStorage.setItem('bim.buildingPreset', preset);
1428	        } catch {
1429	          /* noop */
1430	        }
1431	        return { buildingPreset: preset };
1432	      }),
1433	
1434	    setWorkspaceLayoutPreset: (preset) =>
1435	      set(() => {
1436	        try {
1437	          localStorage.setItem('bim.workspaceLayout', preset);
1438	        } catch {
1439	          /* noop */
1440	        }
1441	        return { workspaceLayoutPreset: preset };
1442	      }),
1443	
1444	    setPerspectiveId: (perspectiveId) =>
1445	      set(() => {
1446	        try {
1447	          localStorage.setItem('bim.perspective', perspectiveId);
1448	        } catch {
1449	          /* noop */
1450	        }
1451	        return { perspectiveId };
1452	      }),
1453	
1454	    setPlanPresentationPreset: (planPresentationPreset) =>
1455	      set(() => {
1456	        try {
1457	          localStorage.setItem('bim.planPresentation', planPresentationPreset);
1458	        } catch {
1459	          /* noop */
1460	        }
1461	        return { planPresentationPreset };
1462	      }),
1463	
1464	    activatePlanView: (planViewElementId) => {
1465	      if (!planViewElementId) {
1466	        set({ activePlanViewId: undefined });
1467	        return;
1468	      }
1469	      const el = get().elementsById[planViewElementId];
1470	      if (!el || el.kind !== 'plan_view') return;
1471	      const preset = el.planPresentation ?? 'default';
1472	      const normalized: PlanPresentationPreset =
1473	        preset === 'opening_focus' || preset === 'room_scheme' ? preset : 'default';
1474	      try {
1475	        localStorage.setItem('bim.planPresentation', normalized);
1476	      } catch {
1477	        /* noop */
1478	      }
1479	      set({
1480	        activePlanViewId: planViewElementId,
1481	        activeViewpointId: undefined,
1482	        activeLevelId: el.levelId,
1483	        planPresentationPreset: normalized,
1484	        viewerMode: 'plan_canvas',
1485	      });
1486	    },
1487	
1488	    setActiveViewpointId: (viewpointElementId) => set({ activeViewpointId: viewpointElementId }),
1489	
1490	    setViewerClipElevMm: (viewerClipElevMm) => set({ viewerClipElevMm }),
1491	
1492	    setViewerClipFloorElevMm: (viewerClipFloorElevMm) => set({ viewerClipFloorElevMm }),
1493	
1494	    setPlanProjectionPrimitives: (planProjectionPrimitives) =>
1495	      planProjectionPrimitives === null
1496	        ? set({ planProjectionPrimitives: null, planRoomSchemeWireReadout: null })
1497	        : set({ planProjectionPrimitives }),
1498	
1499	    setPlanRoomSchemeWireReadout: (planRoomSchemeWireReadout) => set({ planRoomSchemeWireReadout }),
1500	
1501	    setScheduleBudgetHydration: (scheduleBudgetHydration) => set({ scheduleBudgetHydration }),
1502	
1503	    toggleViewerCategoryHidden: (semanticKind) =>
1504	      set(() => {
1505	        const prior = get().viewerCategoryHidden[semanticKind];
1506	        const next = { ...get().viewerCategoryHidden, [semanticKind]: !prior };
1507	        return { viewerCategoryHidden: next };
1508	      }),
1509	
1510	    applyOrbitViewpointPreset: (opts) =>
1511	      set((state) => {
1512	        const LayerKeys = ['wall', 'floor', 'roof', 'stair', 'door', 'window', 'room'] as const;
1513	        let viewerClipElevMm = state.viewerClipElevMm;
1514	        if ('capElevMm' in opts) {
1515	          const v = opts.capElevMm;
1516	          viewerClipElevMm =
1517	            v !== undefined && v !== null && typeof v === 'number' && Number.isFinite(v) ? v : null;
1518	        }
1519	        let viewerClipFloorElevMm = state.viewerClipFloorElevMm;
1520	        if ('floorElevMm' in opts) {
1521	          const v = opts.floorElevMm;
1522	          viewerClipFloorElevMm =
1523	            v !== undefined && v !== null && typeof v === 'number' && Number.isFinite(v) ? v : null;
1524	        }
1525	        let viewerCategoryHidden = state.viewerCategoryHidden;
1526	        if (opts.hideSemanticKinds !== undefined) {
1527	          const hid = new Set(opts.hideSemanticKinds);
1528	          viewerCategoryHidden = { ...state.viewerCategoryHidden };
1529	          for (const lk of LayerKeys) {
1530	            viewerCategoryHidden[lk] = hid.has(lk);
1531	          }
1532	        }
1533	        return {
1534	          viewerClipElevMm,
1535	          viewerClipFloorElevMm,
1536	          viewerCategoryHidden,
1537	        };
1538	      }),
1539	
1540	    setOrbitCameraFromViewpointMm: ({ position, target, up }) =>
1541	      set((state) => ({
1542	        orbitCameraPoseMm: { position, target, up },
1543	        orbitCameraNonce: state.orbitCameraNonce + 1,
1544	      })),
1545	
1546	    setActivity: (e) => set({ activityEvents: e }),
1547	
1548	    setIdentity: (userId, userDisplayName, peerId) =>
1549	      set(() => {
1550	        try {
1551	          sessionStorage.setItem('bim.userId', userId);
1552	
1553	          sessionStorage.setItem('bim.displayName', userDisplayName);
1554	
1555	          sessionStorage.setItem('bim.peerId', peerId);
1556	        } catch {
1557	          /* noop */
1558	        }
1559	
1560	        return { userId, userDisplayName: userDisplayName, peerId };
1561	      }),
1562	  };
1563	});
