21	 *     `[` / `]`).
22	 *   - Keyboard hotkeys: `[` toggles left rail collapsed-vs-expanded; `]`
23	 *     toggles right rail.
24	 *
25	 * Slot props are pure render functions. AppShell does not own canvas /
26	 * rail content — composed surfaces (TopBar, ProjectBrowser, Inspector,
27	 * StatusBar) are wired in by their owning workpackages (A03–A06).
28	 */
29	
30	export interface AppShellProps {
31	  topBar: ReactNode;
32	  leftRail: ReactNode;
33	  /** Compact contents shown when the left rail is collapsed (icon-strip). */
34	  leftRailCollapsed?: ReactNode;
35	  canvas: ReactNode;
36	  rightRail: ReactNode;
37	  statusBar: ReactNode;
38	  /** Initial collapsed state for the left rail. Defaults to false. */
39	  defaultLeftCollapsed?: boolean;
40	  /** Initial collapsed state for the right rail. Defaults to false. */
41	  defaultRightCollapsed?: boolean;
42	  /** Controlled left-rail collapsed state. When provided, overrides internal state. */
43	  leftCollapsed?: boolean;
44	  onLeftCollapsedChange?: (v: boolean) => void;
45	  /** Override the document target for the global `[` / `]` hotkeys.
46	   * Used by tests to scope the listeners. */
47	  hotkeyTarget?: Document | HTMLElement;
48	}
49	
50	export function AppShell({
51	  topBar,
52	  leftRail,
53	  leftRailCollapsed,
54	  canvas,
55	  rightRail,
56	  statusBar,
57	  defaultLeftCollapsed = false,
58	  defaultRightCollapsed = false,
59	  leftCollapsed: leftCollapsedProp,
60	  onLeftCollapsedChange,
61	  hotkeyTarget,
62	}: AppShellProps): JSX.Element {
63	  const { t } = useTranslation();
64	  const [leftCollapsedInternal, setLeftCollapsedInternal] = useState(defaultLeftCollapsed);
65	  const [rightCollapsed, setRightCollapsed] = useState(defaultRightCollapsed);
66	
67	  const isControlled = leftCollapsedProp !== undefined;
68	  const leftCollapsed = isControlled ? leftCollapsedProp : leftCollapsedInternal;
69	  const setLeftCollapsed = useCallback(
70	    (updater: boolean | ((prev: boolean) => boolean)) => {
71	      const next = typeof updater === 'function' ? updater(leftCollapsed) : updater;
72	      if (isControlled) {
73	        onLeftCollapsedChange?.(next);
74	      } else {
75	        setLeftCollapsedInternal(next);
76	      }
77	    },
78	    [isControlled, leftCollapsed, onLeftCollapsedChange],
79	  );
80	
81	  const handleKey = useCallback(
82	    (event: KeyboardEvent | globalThis.KeyboardEvent) => {
83	      if (shouldIgnoreKey(event)) return;
84	      if (event.key === '[') {
85	        event.preventDefault();
86	        setLeftCollapsed((v) => !v);
87	      } else if (event.key === ']') {
88	        event.preventDefault();
89	        setRightCollapsed((v) => !v);
90	      }
91	    },
92	    [setLeftCollapsed],
93	  );
94	
95	  useEffect(() => {
96	    const target: Document | HTMLElement | undefined =
97	      hotkeyTarget ?? (typeof document !== 'undefined' ? document : undefined);
98	    if (!target) return;
99	    const listener = (e: globalThis.KeyboardEvent): void => handleKey(e);
100	    target.addEventListener('keydown', listener as EventListener);
101	    return () => target.removeEventListener('keydown', listener as EventListener);
102	  }, [handleKey, hotkeyTarget]);
103	
104	  const style: CSSProperties = {
105	    display: 'grid',
106	    gridTemplateRows: 'auto minmax(0, 1fr) var(--shell-statusbar-height)',
107	    gridTemplateColumns: gridColumnsForState(leftCollapsed, rightCollapsed),
108	    gridTemplateAreas: `
109	      "topbar topbar topbar"
110	      "leftRail canvas rightRail"
111	      "statusbar statusbar statusbar"
112	    `,
113	    height: '100dvh',
114	    width: '100%',
115	    overflow: 'hidden',
116	    background: 'var(--color-background)',
117	    color: 'var(--color-foreground)',
118	  };
119	
120	  return (
121	    <div
122	      data-testid="app-shell"
123	      data-left-collapsed={leftCollapsed ? 'true' : 'false'}
124	      data-right-collapsed={rightCollapsed ? 'true' : 'false'}
125	      style={style}
126	    >
127	      <div
128	        style={{ gridArea: 'topbar' }}
129	        className="flex items-center border-b border-border bg-surface"
130	      >
131	        {topBar}
132	      </div>
133	      <aside
134	        aria-label={t('workspace.projectBrowser')}
135	        data-testid="app-shell-left-rail"
136	        style={{ gridArea: 'leftRail', minWidth: 0 }}
137	        className="flex flex-col border-r border-border bg-surface"
138	      >
139	        {leftCollapsed ? (leftRailCollapsed ?? null) : leftRail}
140	      </aside>
141	      <main
142	        aria-label={t('workspace.canvasLabel')}
143	        data-testid="app-shell-canvas"
144	        style={{ gridArea: 'canvas', minWidth: 0, minHeight: 0 }}
145	        className="relative overflow-hidden bg-background"
146	      >
147	        {canvas}
148	      </main>
149	      <aside
150	        aria-label={t('workspace.inspectorLabel')}
151	        data-testid="app-shell-right-rail"
152	        style={{ gridArea: 'rightRail', minWidth: 0, minHeight: 0, overflow: 'hidden' }}
153	        className="flex flex-col border-l border-border bg-surface"
154	        hidden={rightCollapsed}
155	      >
156	        {rightRail}
157	      </aside>
158	      <footer
159	        style={{ gridArea: 'statusbar' }}
160	        className="flex items-center border-t border-border bg-surface text-xs"
161	      >
162	        {statusBar}
163	      </footer>
164	    </div>
165	  );
166	}
167	
168	function gridColumnsForState(leftCollapsed: boolean, rightCollapsed: boolean): string {
169	  const left = leftCollapsed
170	    ? 'var(--shell-rail-left-collapsed-width)'
171	    : 'var(--shell-rail-left-width)';
172	  const right = rightCollapsed ? '0' : 'var(--shell-rail-right-width)';
173	  return `${left} minmax(0, 1fr) ${right}`;
174	}
175	
176	function shouldIgnoreKey(event: KeyboardEvent | globalThis.KeyboardEvent): boolean {
177	  const target = event.target as HTMLElement | null;
178	  if (!target) return false;
179	  if (event.metaKey || event.ctrlKey || event.altKey) return true;
180	  const tag = target.tagName;
181	  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
182	  if (target.isContentEditable) return true;
183	  return false;
184	}

