1	/**
2	 * Plan canvas state — spec §14.
3	 *
4	 * Pure-state controllers that compose the redesigned plan canvas. Each
5	 * controller is testable without DOM/canvas; the visual layer in
6	 * `PlanCanvas.tsx` consumes them in WP-UI-B01 and beyond.
7	 *
8	 * This module composes WP-UI-B01 (drafting paint state), WP-UI-B02
9	 * (snap engine + pointer classifier), and WP-UI-B03 (plan camera).
10	 */
11	
12	import {
13	  CATEGORY_LINE_RULES,
14	  gridVisibilityFor,
15	  HATCH_SPECS,
16	  hatchVisibleAt,
17	  lineWidthPxFor,
18	  type HatchSpec,
19	} from './draftingStandards';
20	
21	/* ────────────────────────────────────────────────────────────────────── */
22	/* B01 — Drafting paint state                                              */
23	/* ────────────────────────────────────────────────────────────────────── */
24	
25	export interface DraftingPaint {
26	  paperToken: '--draft-paper';
27	  grid: { showMajor: boolean; showMinor: boolean };
28	  lineWidthPx: (token: keyof typeof CATEGORY_LINE_RULES) => number;
29	  visibleHatches: HatchSpec[];
30	}
31	
32	/** Resolve the §14.2 drafting paint set for a given plot scale. */
33	export function draftingPaintFor(plotScale: number): DraftingPaint {
34	  const grid = gridVisibilityFor(plotScale);
35	  const visibleHatches = Object.values(HATCH_SPECS).filter((h) => hatchVisibleAt(plotScale, h));
36	  return {
37	    paperToken: '--draft-paper',
38	    grid,
39	    visibleHatches,
40	    lineWidthPx(role) {
41	      const rule = CATEGORY_LINE_RULES[role as string];
42	      if (!rule) return 1;
43	      return lineWidthPxFor(rule.weight, plotScale);
44	    },
45	  };
46	}
47	
48	/* ────────────────────────────────────────────────────────────────────── */
49	/* B02 — Snap engine                                                        */
50	/* ────────────────────────────────────────────────────────────────────── */
51	
52	export type SnapMode =
53	  | 'endpoint'
54	  | 'midpoint'
55	  | 'intersection'
56	  | 'perpendicular'
57	  | 'parallel'
58	  | 'tangent'
59	  | 'nearest'
60	  | 'grid'
61	  | 'polar';
62	
63	export const SNAP_DEFAULTS: Record<SnapMode, boolean> = {
64	  endpoint: true,
65	  midpoint: true,
66	  intersection: true,
67	  perpendicular: true,
68	  parallel: true,
69	  tangent: false,
70	  nearest: true,
71	  grid: true,
72	  polar: true,
73	};
74	
75	export interface SnapCandidate {
76	  mode: SnapMode;
77	  /** World-space mm coordinates of the snap target. */
78	  xMm: number;
79	  yMm: number;
80	  /** Optional human label appended to the pill (`from <endpoint>`). */
81	  detail?: string;
82	}
83	
84	export class SnapEngine {
85	  private modes: Record<SnapMode, boolean>;
86	
87	  constructor(initial: Partial<Record<SnapMode, boolean>> = {}) {
88	    this.modes = { ...SNAP_DEFAULTS, ...initial };
89	  }
90	
91	  isOn(mode: SnapMode): boolean {
92	    return this.modes[mode];
93	  }
94	
95	  toggle(mode: SnapMode): void {
96	    this.modes[mode] = !this.modes[mode];
97	  }
98	
99	  setOn(mode: SnapMode, on: boolean): void {
100	    this.modes[mode] = on;
101	  }
102	
103	  /** Cycle through snap modes (`F3`). Loops endpoint → midpoint → … →
104	   * polar → endpoint. Disables every other mode while one is active. */
105	  cycleExclusive(): SnapMode {
106	    const order: SnapMode[] = [
107	      'endpoint',
108	      'midpoint',
109	      'intersection',
110	      'perpendicular',
111	      'parallel',
112	      'tangent',
113	      'nearest',
114	      'grid',
115	      'polar',
116	    ];
117	    const currentIdx = order.findIndex((m) => this.modes[m]);
118	    const nextIdx = (currentIdx + 1) % order.length;
119	    for (const m of order) this.modes[m] = false;
120	    this.modes[order[nextIdx]!] = true;
121	    return order[nextIdx]!;
122	  }
123	
124	  /** Resolve cursor against a list of candidates and return the
125	   * highest-priority snap. */
126	  resolve(candidates: SnapCandidate[]): SnapCandidate | null {
127	    const priority: SnapMode[] = [
128	      'endpoint',
129	      'midpoint',
130	      'intersection',
131	      'perpendicular',
132	      'parallel',
133	      'tangent',
134	      'nearest',
135	      'grid',
136	      'polar',
137	    ];
138	    for (const mode of priority) {
139	      if (!this.modes[mode]) continue;
140	      const hit = candidates.find((c) => c.mode === mode);
141	      if (hit) return hit;
142	    }
143	    return null;
144	  }
145	
146	  /** Returns a labelled pill for the given snap, ready for §14.4
147	   * status-bar display. */
148	  pillLabel(candidate: SnapCandidate): string {
149	    const detail = candidate.detail ? ` · ${candidate.detail}` : '';
150	    return `${candidate.mode}${detail}`;
151	  }
152	
153	  snapshot(): Record<SnapMode, boolean> {
154	    return { ...this.modes };
155	  }
156	}
157	
158	/* ────────────────────────────────────────────────────────────────────── */
159	/* B02 — Pointer classifier                                                 */
160	/* ────────────────────────────────────────────────────────────────────── */
161	
162	export type PointerIntent =
163	  | 'pan'
164	  | 'marquee-window'
165	  | 'marquee-crossing'
166	  | 'drag-move'
167	  | 'add-to-selection'
168	  | 'toggle-selection'
169	  | 'draw'
170	  | 'idle';
171	
172	export interface PointerStartLike {
173	  button: number;
174	  spacePressed?: boolean;
175	  shiftKey?: boolean;
176	  altKey?: boolean;
177	  ctrlKey?: boolean;
178	  metaKey?: boolean;
179	  /** Active drawing tool from §16. */
180	  activeTool?:
181	    | 'select'
182	    | 'wall'
183	    | 'door'
184	    | 'window'
185	    | 'floor'
186	    | 'roof'
187	    | 'stair'
188	    | 'room'
189	    | 'dimension'
190	    | 'section'
191	    | 'tag';
192	  dragDirection?: 'left-to-right' | 'right-to-left' | null;
193	}
194	
195	/** Map a pointer-down event to a §14.3 intent. */
196	export function classifyPointerStart(event: PointerStartLike): PointerIntent {
197	  if (event.spacePressed && event.button === 0) return 'pan';
198	  if (event.button === 1) return 'pan'; // middle-click pan
199	  if (event.activeTool && event.activeTool !== 'select') return 'draw';
200	  if (event.shiftKey && event.button === 0) return 'add-to-selection';
201	  if (event.altKey && event.button === 0) return 'toggle-selection';
202	  if (event.button === 0) {
203	    if (event.dragDirection === 'right-to-left') return 'marquee-crossing';
204	    if (event.dragDirection === 'left-to-right') return 'marquee-window';
205	    return 'drag-move';
206	  }
207	  return 'idle';
208	}
209	
210	/* ────────────────────────────────────────────────────────────────────── */
211	/* B03 — Plan camera                                                        */
212	/* ────────────────────────────────────────────────────────────────────── */
213	
214	export interface PlanCameraSnapshot {
215	  plotScale: number; // 1:N denominator
216	  centerMm: { xMm: number; yMm: number };
217	  activeLevelId: string;
218	}
