1	/**
2	 * Drafting standards — spec §9.10 + §26.
3	 *
4	 * Single source of truth for plan-canvas line weights, dash patterns,
5	 * stroke colors (drafting tokens), and category-specific role mappings.
6	 * Consumed by `PlanCanvas.tsx` and `plan/symbology/*` so a token / spec
7	 * update lights up everywhere.
8	 */
9	
10	export type LineWeightTokenName =
11	  | '--draft-lw-cut-major'
12	  | '--draft-lw-cut-minor'
13	  | '--draft-lw-projection-major'
14	  | '--draft-lw-projection-minor'
15	  | '--draft-lw-hidden'
16	  | '--draft-lw-witness'
17	  | '--draft-lw-construction';
18	
19	export type DraftingColorTokenName =
20	  | '--draft-paper'
21	  | '--draft-grid-major'
22	  | '--draft-grid-minor'
23	  | '--draft-construction-blue'
24	  | '--draft-witness'
25	  | '--draft-cut'
26	  | '--draft-projection'
27	  | '--draft-hidden'
28	  | '--draft-selection'
29	  | '--draft-hover'
30	  | '--draft-snap';
31	
32	export type CategoryColorTokenName =
33	  | '--cat-wall'
34	  | '--cat-floor'
35	  | '--cat-roof'
36	  | '--cat-door'
37	  | '--cat-window'
38	  | '--cat-stair'
39	  | '--cat-railing'
40	  | '--cat-room'
41	  | '--cat-site'
42	  | '--cat-section'
43	  | '--cat-sheet';
44	
45	/** Canonical line-weight px values at 1:50 plot scale. Mirrors §9.10. */
46	export const LINE_WEIGHT_PX_AT_1_50: Record<LineWeightTokenName, number> = {
47	  '--draft-lw-cut-major': 2.0,
48	  '--draft-lw-cut-minor': 1.4,
49	  '--draft-lw-projection-major': 1.0,
50	  '--draft-lw-projection-minor': 0.7,
51	  '--draft-lw-hidden': 0.7,
52	  '--draft-lw-witness': 0.5,
53	  '--draft-lw-construction': 0.5,
54	};
55	
56	/** Reference plot scale anchor for `LINE_WEIGHT_PX_AT_1_50`. */
57	export const REFERENCE_PLOT_SCALE = 50;
58	
59	/** Compute the px width of a line-weight token at an arbitrary plot
60	 * scale (where `plotScale` is the denominator of `1:N`). Larger
61	 * denominators (e.g. 1:200) shrink the line; smaller (1:5) widen it. */
62	export function lineWidthPxFor(token: LineWeightTokenName, plotScale: number): number {
63	  const base = LINE_WEIGHT_PX_AT_1_50[token];
64	  if (!Number.isFinite(plotScale) || plotScale <= 0) return base;
65	  return base * (REFERENCE_PLOT_SCALE / plotScale);
66	}
67	
68	/** Spec §26 stroke style for category line roles. */
69	export type DashStyle =
70	  | { kind: 'solid' }
71	  | { kind: 'dashed'; on: number; off: number }
72	  | { kind: 'dash-dot'; pattern: [number, number, number, number] };
73	
74	export interface CategoryLineRule {
75	  weight: LineWeightTokenName;
76	  color: DraftingColorTokenName | CategoryColorTokenName;
77	  dash: DashStyle;
78	  /** Multiplicative opacity [0..1]; used by §26 below-cut projections. */
79	  opacity?: number;
80	}
81	
82	/** §26 line-role table for the redesign. Keys are the canonical role names
83	 * referenced by symbology; values plug straight into the renderer. */
84	export const CATEGORY_LINE_RULES: Record<string, CategoryLineRule> = {
85	  'wall.cut': {
86	    weight: '--draft-lw-cut-major',
87	    color: '--draft-cut',
88	    dash: { kind: 'solid' },
89	  },
90	  'door.cut': {
91	    weight: '--draft-lw-cut-minor',
92	    color: '--draft-cut',
93	    dash: { kind: 'solid' },
94	  },
95	  'window.cut': {
96	    weight: '--draft-lw-cut-minor',
97	    color: '--draft-cut',
98	    dash: { kind: 'solid' },
99	  },
100	  'floor.projection': {
101	    weight: '--draft-lw-projection-minor',
102	    color: '--draft-projection',
103	    dash: { kind: 'solid' },
104	    opacity: 0.6,
105	  },
106	  'roof.projection': {
107	    weight: '--draft-lw-projection-minor',
108	    color: '--draft-projection',
109	    dash: { kind: 'dash-dot', pattern: [4, 2, 1, 2] },
110	  },
111	  'stair.tread': {
112	    weight: '--draft-lw-cut-minor',
113	    color: '--draft-cut',
114	    dash: { kind: 'solid' },
115	  },
116	  'stair.direction': {
117	    weight: '--draft-lw-projection-major',
118	    color: '--draft-projection',
119	    dash: { kind: 'solid' },
120	  },
121	  hidden: {
122	    weight: '--draft-lw-hidden',
123	    color: '--draft-hidden',
124	    dash: { kind: 'dashed', on: 4, off: 3 },
125	  },
126	  'dimension.witness': {
127	    weight: '--draft-lw-witness',
128	    color: '--draft-witness',
129	    dash: { kind: 'solid' },
130	  },
131	  construction: {
132	    weight: '--draft-lw-construction',
133	    color: '--draft-construction-blue',
134	    dash: { kind: 'solid' },
135	  },
136	};
137	
138	/** Convert a `DashStyle` to an SVG `stroke-dasharray` value (or null for
139	 * solid). Multiplied by `widthPx` to keep the dash gauge proportional. */
140	export function dashArray(style: DashStyle, widthPx: number): string | null {
141	  if (style.kind === 'solid') return null;
142	  if (style.kind === 'dashed') {
143	    return `${style.on * widthPx} ${style.off * widthPx}`;
144	  }
145	  return style.pattern.map((n) => n * widthPx).join(' ');
146	}
147	
148	/* ────────────────────────────────────────────────────────────────────── */
149	/* Hatches — spec §26                                                      */
150	/* ────────────────────────────────────────────────────────────────────── */
151	
152	export type HatchKind = 'wall.concrete' | 'floor.timber' | 'site.lawn';
153	
154	export interface HatchSpec {
155	  kind: HatchKind;
156	  /** Stroke width in mm at the 1:50 reference. */
157	  widthMm: number;
158	  /** Spacing between strokes in mm. */
159	  spacingMm: number;
160	  /** Angle in degrees CCW from +x. */
161	  angleDeg: number;
162	  /** Token used for the stroke. */
163	  color: DraftingColorTokenName | CategoryColorTokenName;
164	  /** Min plot scale (denominator) at which the hatch becomes visible. */
165	  visibleAtScaleAtMost: number;
166	}
167	
168	export const HATCH_SPECS: Record<HatchKind, HatchSpec> = {
169	  'wall.concrete': {
170	    kind: 'wall.concrete',
171	    widthMm: 0.5,
172	    spacingMm: 1,
173	    angleDeg: 45,
174	    color: '--cat-wall',
175	    visibleAtScaleAtMost: 200,
176	  },
177	  'floor.timber': {
178	    kind: 'floor.timber',
179	    widthMm: 0.5,
180	    spacingMm: 0.7,
181	    angleDeg: 0,
182	    color: '--cat-floor',
183	    visibleAtScaleAtMost: 200,
184	  },
185	  'site.lawn': {
186	    kind: 'site.lawn',
187	    widthMm: 0.3,
188	    spacingMm: 1.5,
189	    angleDeg: 90,
190	    color: '--cat-site',
191	    visibleAtScaleAtMost: 200,
192	  },
193	};
194	
195	/** True when a hatch should render at the current plot scale (1:N). */
196	export function hatchVisibleAt(plotScale: number, hatch: HatchSpec): boolean {
197	  return plotScale <= hatch.visibleAtScaleAtMost;
198	}
199	
200	/* ────────────────────────────────────────────────────────────────────── */
201	/* Grid step                                                               */
202	/* ────────────────────────────────────────────────────────────────────── */
203	
204	/** Per §14.5 / §14.2: major grid 1 m, minor grid 100 mm; minor only
205	 * shown at 1:100 or finer; no grid above 1:200. */
206	export interface GridVisibility {
207	  showMajor: boolean;
208	  showMinor: boolean;
209	}
210	
211	export function gridVisibilityFor(plotScale: number): GridVisibility {
212	  if (plotScale <= 100) return { showMajor: true, showMinor: true };
213	  if (plotScale <= 200) return { showMajor: true, showMinor: false };
214	  return { showMajor: false, showMinor: false };
215	}
