  camera.left = -hh * asp;
  camera.right = hh * asp;
  camera.top = hh;
  camera.bottom = -hh;
  camera.position.set(camRef.current.camX, 320, camRef.current.camZ);
  camera.lookAt(camRef.current.camX, 0, camRef.current.camZ);
  camera.updateProjectionMatrix();
  setHalfUi(camRef.current.half);
