  if (forcePan) {
    const rr = rayToPlanMm(rnd, camNow, ev.clientX, ev.clientY);
    if (!rr) return;
    dragRef.current = {
      dragging: true,
      lastXmm: rr.xMm,
      lastZmm: rr.yMm,
      camX: camRef.current.camX,
