    const ray = new THREE.Raycaster();
    ray.setFromCamera(
      new THREE.Vector2(
        ((ev.clientX - rectBox.left) / rectBox.width) * 2 - 1,
        -(((ev.clientY - rectBox.top) / rectBox.height) * 2 - 1),
      ),
      camNow,
